const ids = (($json.body || {}).profileIds || [])
  .filter(x => typeof x === 'string' && x && x !== '-1');
// Base64-encoded JSON array: n8n's queryReplacement splits plain values on
// commas (a multi-id CSV would reach SQL as $1 = first id only); base64 has
// no commas so the whole list survives as ONE parameter. Base64 of [] is
// "W10=", never empty, so no empty-list sentinel is needed.
return [{ json: { b64Ids: Buffer.from(JSON.stringify(ids)).toString('base64'), profileCount: ids.length } }];

