const src = $('Split Out').item.json;
let outcome = null, summary = '';
try {
  const content = $json.choices?.[0]?.message?.content;
  if (content) {
    const parsed = JSON.parse(content);
    const allowed = ['order_collected','owner_needed','in_dialog','question_closed'];
    if (allowed.includes(parsed.outcome)) outcome = parsed.outcome;
    if (typeof parsed.summary === 'string') summary = parsed.summary.slice(0, 120);
  }
} catch (e) { /* outcome stays null */ }
// outcome === null means OpenAI errored or returned garbage. Mark the row failed
// so Aggregate drops it from the upsert: the watermark must NOT advance and any
// previously stored outcome/summary must survive (spec 4.3 — keep previous
// outcome); the untouched watermark makes the next call retry naturally.
return { json: {
  failed: outcome === null,
  session_id: src.session_id, profile_id: src.profile_id, chat_id: src.chat_id,
  outcome: outcome || 'in_dialog', summary,
  last_history_id: src.max_id, last_message_at_ms: src.last_message_at_ms
} };

const all = $input.all().map(i => i.json);
// Drop classification failures entirely — no upsert row, watermark untouched,
// retried on the next call. truncated stays keyed to the raw total so a real
// backlog still triggers the client's drain loop (failures deliberately do NOT
// set truncated: an OpenAI outage should degrade quietly, not hammer retries).
const ok = all.filter(r => !r.failed);
const rows = ok.slice(0, 20);
const total = Number($('Find Changed Sessions').first().json.total);
return [{ json: {
  b64: Buffer.from(JSON.stringify(rows)).toString('base64'),
  classified: rows.length,
  truncated: total > 20
} }];

let classified = 0, truncated = false;
try {
  const agg = $('Aggregate').first();
  if (agg && agg.json) {
    classified = agg.json.classified ?? 0;
    truncated = agg.json.truncated ?? false;
  }
} catch (e) { /* Aggregate did not run (empty branch) */ }
const outcomes = $('Fetch Outcomes').all()
  .map(i => i.json)
  .filter(o => o && o.profileId !== undefined);
return [{ json: { success: true, classified, truncated, outcomes } }];
